import React from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
    Send,
    Paperclip,
    File as FileIcon,
    Users,
    MessageSquare,
    MoreVertical,
    Download,
    Monitor,
} from 'lucide-react';
import { format } from 'date-fns';
import { User, Message, FileData } from '@/types/websocket';

interface ChatItem {
    id: string;
    userId: string;
    userName: string;
    timestamp: Date | string;
    content?: string;
    isFile?: boolean;
    url?: string;
    name?: string;
    size?: number;
    type?: string;
}

interface ChatPanelProps {
    showChat: boolean;
    activeTab: 'chat' | 'participants';
    setActiveTab: (tab: 'chat' | 'participants') => void;
    messages: Message[];
    files: FileData[];
    users: User[];
    currentUser: User | undefined;
    isHost: boolean;
    waitingUsers: User[];
    admitUser: (userId: string) => void;
    denyUser: (userId: string) => void;
    admitAllWaitingUsers: () => void;
    promoteToCoHost: (userId: string) => void;
    demoteFromCoHost: (userId: string) => void;
    muteUser: (userId: string) => void;
    kickUser: (userId: string) => void;
    messagesEndRef: React.RefObject<HTMLDivElement>;
    handleSendMessage: (e: React.FormEvent) => void;
    newMessage: string;
    setNewMessage: (message: string) => void;
    fileInputRef: React.RefObject<HTMLInputElement>;
    handleFileUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    triggerFileUpload: () => void;
    isUploading: boolean;
    presentFile: (file: FileData) => void;
}

const ChatPanel: React.FC<ChatPanelProps> = ({
    showChat,
    activeTab,
    setActiveTab,
    messages,
    files,
    users,
    currentUser,
    isHost,
    waitingUsers,
    admitUser,
    denyUser,
    admitAllWaitingUsers,
    promoteToCoHost,
    demoteFromCoHost,
    muteUser,
    kickUser,
    messagesEndRef,
    handleSendMessage,
    newMessage,
    setNewMessage,
    fileInputRef,
    handleFileUpload,
    triggerFileUpload,
    isUploading,
    presentFile,
}) => {
    return (
        <div
            className={`fixed right-0 top-16 bottom-0 w-full md:w-80 bg-background border-l transition-transform duration-300 flex flex-col z-40 ${showChat ? 'translate-x-0' : 'translate-x-full'
                }`}
        >
            {/* Tabs */}
            <div className='flex items-center border-b'>
                <Button
                    variant='ghost'
                    className={`flex-1 rounded-none border-b-2 ${activeTab === 'chat'
                        ? 'border-primary text-primary'
                        : 'border-transparent text-muted-foreground'
                        }`}
                    onClick={() => setActiveTab('chat')}
                >
                    <MessageSquare className='w-4 h-4 mr-2' /> Chat
                </Button>
                <Button
                    variant='ghost'
                    className={`flex-1 rounded-none border-b-2 ${activeTab === 'participants'
                        ? 'border-primary text-primary'
                        : 'border-transparent text-muted-foreground'
                        }`}
                    onClick={() => setActiveTab('participants')}
                >
                    <Users className='w-4 h-4 mr-2' /> Participants
                    {waitingUsers.length > 0 && (
                        <Badge
                            variant='destructive'
                            className='ml-2 h-5 w-5 p-0 flex items-center justify-center rounded-full text-[10px]'
                        >
                            {waitingUsers.length}
                        </Badge>
                    )}
                </Button>
            </div>

            {/* Tab Content */}
            <div className='flex-1 overflow-hidden flex flex-col'>
                {activeTab === 'chat' ? (
                    // Chat Tab
                    <div className='flex-1 flex flex-col h-full'>
                        <ScrollArea className='flex-1 p-4'>
                            <div className='space-y-4'>
                                {[
                                    ...messages,
                                    ...files.map((f) => ({
                                        ...f,
                                        id: `file-${f.id}`,
                                        isFile: true,
                                        content: f.name,
                                    })),
                                ]
                                    .sort(
                                        (a, b) =>
                                            new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
                                    )
                                    .map((item: unknown) => {
                                        const chatItem = item as ChatItem;
                                        const isSystemMessage = chatItem.userId === 'system';
                                        if (isSystemMessage) {
                                            return (
                                                <div key={chatItem.id} className='flex justify-center my-2'>
                                                    <div className='bg-muted/50 px-4 py-1 rounded-full'>
                                                        <span className='text-xs text-muted-foreground'>
                                                            {chatItem.content}
                                                        </span>
                                                    </div>
                                                </div>
                                            );
                                        }
                                        return (
                                            <div key={chatItem.id} className='flex gap-3'>
                                                <Avatar className='h-8 w-8 mt-1'>
                                                    <AvatarImage
                                                        src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${chatItem.userName}`}
                                                    />
                                                    <AvatarFallback>
                                                        {chatItem.userName.substring(0, 2).toUpperCase()}
                                                    </AvatarFallback>
                                                </Avatar>
                                                <div className='flex flex-col gap-1 max-w-[85%]'>
                                                    <div className='flex items-baseline gap-2'>
                                                        <span className='text-sm font-semibold'>
                                                            {chatItem.userName}
                                                        </span>
                                                        <span className='text-xs text-muted-foreground'>
                                                            {format(new Date(chatItem.timestamp), 'HH:mm')}
                                                        </span>
                                                    </div>
                                                    {chatItem.isFile ? (
                                                        (() => {
                                                            const fileUrl = chatItem.url!.startsWith('http')
                                                                ? chatItem.url
                                                                : `${import.meta.env.VITE_WS_URL || 'http://localhost:3001'
                                                                }${chatItem.url}`;
                                                            return (
                                                                <div className='flex flex-col gap-2'>
                                                                    <div className='bg-muted p-3 rounded-lg rounded-tl-none border flex items-center gap-3 group hover:bg-muted/80 transition-colors'>
                                                                        <div
                                                                            className='bg-background p-2 rounded-md cursor-pointer'
                                                                            onClick={() => window.open(fileUrl, '_blank')}
                                                                        >
                                                                            <FileIcon className='w-6 h-6 text-primary' />
                                                                        </div>
                                                                        <div
                                                                            className='flex-1 min-w-0 cursor-pointer'
                                                                            onClick={() => window.open(fileUrl, '_blank')}
                                                                        >
                                                                            <p className='text-sm font-medium text-primary underline-offset-4 group-hover:underline truncate'>
                                                                                {chatItem.name}
                                                                            </p>
                                                                            <p className='text-xs text-muted-foreground'>
                                                                                {(chatItem.size! / 1024).toFixed(1)} KB
                                                                            </p>
                                                                        </div>
                                                                        <Button
                                                                            variant='ghost'
                                                                            size='icon'
                                                                            className='h-8 w-8'
                                                                            title='Download'
                                                                            onClick={(e) => {
                                                                                e.stopPropagation();
                                                                                const link = document.createElement('a');
                                                                                link.href = fileUrl!;
                                                                                link.download = chatItem.name!;
                                                                                link.target = '_blank';
                                                                                document.body.appendChild(link);
                                                                                link.click();
                                                                                document.body.removeChild(link);
                                                                            }}
                                                                        >
                                                                            <Download className='h-4 w-4' />
                                                                        </Button>
                                                                    </div>
                                                                    {(isHost || currentUser?.isCoHost) &&
                                                                        /\.(mp4|webm|ogg)$/i.test(chatItem.name!) && (
                                                                            <Button
                                                                                size='sm'
                                                                                variant='secondary'
                                                                                className='w-full'
                                                                                onClick={() => presentFile(chatItem as any)}
                                                                            >
                                                                                <Monitor className='w-4 h-4 mr-2' /> Play in Stage
                                                                            </Button>
                                                                        )}
                                                                </div>
                                                            );
                                                        })()
                                                    ) : (
                                                        <div className='bg-primary/10 p-3 rounded-lg rounded-tl-none text-sm'>
                                                            {chatItem.content}
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        );
                                    })}
                                <div ref={messagesEndRef} />
                            </div>
                        </ScrollArea>
                        <div className='p-4 border-t bg-background/50 backdrop-blur-sm'>
                            <form onSubmit={handleSendMessage} className='flex gap-2'>
                                <input
                                    type='file'
                                    ref={fileInputRef}
                                    className='hidden'
                                    onChange={handleFileUpload}
                                />
                                <Button
                                    type='button'
                                    variant='ghost'
                                    size='icon'
                                    onClick={triggerFileUpload}
                                    disabled={isUploading}
                                >
                                    <Paperclip className='w-5 h-5 text-muted-foreground' />
                                </Button>
                                <Input
                                    value={newMessage}
                                    onChange={(e) => setNewMessage(e.target.value)}
                                    placeholder='Type a message...'
                                    className='flex-1'
                                />
                                <Button type='submit' size='icon' disabled={!newMessage.trim()}>
                                    <Send className='w-5 h-5' />
                                </Button>
                            </form>
                        </div>
                    </div>
                ) : (
                    <ScrollArea className='flex-1 p-4'>
                        {waitingUsers.length > 0 && (
                            <div className='mb-6'>
                                <h3 className='text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3'>
                                    Waiting Room ({waitingUsers.length})
                                </h3>
                                <div className='space-y-4'>
                                    {waitingUsers.map((user) => (
                                        <div
                                            key={user.id}
                                            className='flex items-center justify-between p-2 rounded-lg bg-muted/50'
                                        >
                                            <div className='flex items-center gap-2'>
                                                <Avatar className='h-8 w-8'>
                                                    <AvatarImage
                                                        src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.name}`}
                                                    />
                                                    <AvatarFallback>{user.name[0]}</AvatarFallback>
                                                </Avatar>
                                                <div className='flex flex-col'>
                                                    <span className='text-sm font-medium'>{user.name}</span>
                                                    <span className='text-xs text-muted-foreground'>Waiting...</span>
                                                </div>
                                            </div>
                                            <div className='flex items-center gap-1'>
                                                <Button
                                                    size='icon'
                                                    variant='ghost'
                                                    className='h-7 w-7 text-green-500 hover:text-green-600 hover:bg-green-500/10'
                                                    onClick={() => admitUser(user.id)}
                                                >
                                                    <span className='sr-only'>Admit</span>
                                                    <Users className='h-4 w-4' />
                                                </Button>
                                                <Button
                                                    size='icon'
                                                    variant='ghost'
                                                    className='h-7 w-7 text-red-500 hover:text-red-600 hover:bg-red-500/10'
                                                    onClick={() => denyUser(user.id)}
                                                >
                                                    <span className='sr-only'>Deny</span>
                                                    <Users className='h-4 w-4 rotate-45' />
                                                </Button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                                <div className='flex justify-end mt-2'>
                                    <Button
                                        variant='outline'
                                        size='sm'
                                        onClick={admitAllWaitingUsers}
                                        className='text-xs'
                                    >
                                        Admit All
                                    </Button>
                                </div>
                                <div className='h-px bg-border my-4' />
                            </div>
                        )}

                        <h3 className='text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3'>
                            In Meeting ({users.length})
                        </h3>
                        <div className='space-y-4'>
                            {users.map((participant) => (
                                <div
                                    key={participant.id}
                                    className={`flex items-center gap-3 p-2 rounded-lg ${participant.isHost
                                        ? 'bg-primary/10 border border-primary/20'
                                        : participant.isCoHost
                                            ? 'bg-secondary/50 border border-secondary'
                                            : ''
                                        }`}
                                >
                                    <Avatar className='h-8 w-8'>
                                        <AvatarImage
                                            src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${participant.name}`}
                                        />
                                        <AvatarFallback>
                                            {participant.name.substring(0, 2).toUpperCase()}
                                        </AvatarFallback>
                                    </Avatar>
                                    <div className='flex flex-col flex-1'>
                                        <span className='text-sm font-medium leading-none'>
                                            {participant.name}
                                        </span>
                                        <span className='text-xs text-muted-foreground'>Online</span>
                                    </div>
                                    {participant.isHost && (
                                        <Badge variant='default' className='text-xs'>
                                            Host
                                        </Badge>
                                    )}
                                    {participant.isCoHost && !participant.isHost && (
                                        <Badge variant='secondary' className='text-xs'>
                                            Co-Host
                                        </Badge>
                                    )}
                                    {(isHost || users.find((u) => u.id === users[0]?.id)?.isCoHost) &&
                                        !participant.isHost && (
                                            <DropdownMenu>
                                                <DropdownMenuTrigger asChild>
                                                    <Button variant='ghost' size='icon' className='h-6 w-6'>
                                                        <MoreVertical className='h-4 w-4' />
                                                    </Button>
                                                </DropdownMenuTrigger>
                                                <DropdownMenuContent align='end'>
                                                    {participant.isCoHost ? (
                                                        <DropdownMenuItem
                                                            onClick={() => demoteFromCoHost(participant.id)}
                                                        >
                                                            Demote from Co-Host
                                                        </DropdownMenuItem>
                                                    ) : (
                                                        <DropdownMenuItem
                                                            onClick={() => promoteToCoHost(participant.id)}
                                                        >
                                                            Promote to Co-Host
                                                        </DropdownMenuItem>
                                                    )}
                                                    <DropdownMenuItem onClick={() => muteUser(participant.id)}>
                                                        Mute User
                                                    </DropdownMenuItem>
                                                    <DropdownMenuItem
                                                        onClick={() => kickUser(participant.id)}
                                                        className='text-red-600 focus:text-red-600 focus:bg-red-100'
                                                    >
                                                        Kick User
                                                    </DropdownMenuItem>
                                                </DropdownMenuContent>
                                            </DropdownMenu>
                                        )}
                                </div>
                            ))}
                        </div>
                    </ScrollArea>
                )}
            </div>
        </div>
    );
};

export default ChatPanel;

import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

// Moved Organization type to a separate file or just keep it here if we accept the warning for now, 
// but to fix the warning we should probably move it. 
// However, for now I will just fix the 'any' errors.
export type Organization = {
    id: string;
    name: string;
    slug: string;
    owner_id: string;
    created_at: string;
    role?: 'owner' | 'admin' | 'member';
};

type OrganizationContextType = {
    organizations: Organization[];
    currentOrganization: Organization | null;
    setCurrentOrganization: (org: Organization | null) => void;
    isLoading: boolean;
    createOrganization: (name: string, slug: string) => Promise<void>;
    refreshOrganizations: () => Promise<void>;
    addMember: (userId: string, role?: 'admin' | 'member') => Promise<void>;
    removeMember: (userId: string) => Promise<void>;
};

const OrganizationContext = createContext<OrganizationContextType | undefined>(undefined);

export const OrganizationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const [organizations, setOrganizations] = useState<Organization[]>([]);
    const [currentOrganization, setCurrentOrganization] = useState<Organization | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    const fetchOrganizations = useCallback(async () => {
        if (!user) {
            setOrganizations([]);
            setCurrentOrganization(null);
            setIsLoading(false);
            return;
        }

        try {
            setIsLoading(true);
            const { data, error } = await supabase
                .from('organizations')
                .select(`
          *,
          organization_members!inner (
            role
          )
        `)
                .eq('organization_members.user_id', user.id);

            if (error) throw error;

            const orgs = (data as unknown[]).map((org: unknown) => {
                const o = org as Organization & { organization_members: { role: 'owner' | 'admin' | 'member' }[] };
                return {
                    ...o,
                    role: o.organization_members[0]?.role,
                };
            });

            setOrganizations(orgs);

            // Restore selected org from local storage or default to first
            const savedOrgId = localStorage.getItem('selectedOrgId');
            if (savedOrgId) {
                const savedOrg = orgs.find((o: Organization) => o.id === savedOrgId);
                if (savedOrg) setCurrentOrganization(savedOrg);
                else if (orgs.length > 0) setCurrentOrganization(orgs[0]);
            } else if (orgs.length > 0) {
                setCurrentOrganization(orgs[0]);
            }
        } catch (error) {
            console.error('Error fetching organizations:', error);
            toast.error('Failed to load organizations');
        } finally {
            setIsLoading(false);
        }
    }, [user]);

    useEffect(() => {
        fetchOrganizations();
    }, [fetchOrganizations]);

    useEffect(() => {
        if (currentOrganization) {
            localStorage.setItem('selectedOrgId', currentOrganization.id);
        } else {
            localStorage.removeItem('selectedOrgId');
        }
    }, [currentOrganization]);

    const createOrganization = async (name: string, slug: string) => {
        if (!user) return;

        try {
            const { data, error } = await supabase
                .from('organizations')
                .insert({
                    name,
                    slug,
                    owner_id: user.id,
                })
                .select()
                .single();

            if (error) throw error;

            toast.success('Organization created successfully');
            await fetchOrganizations();
            setCurrentOrganization({ ...data, role: 'owner' }); // Optimistic update
        } catch (error: unknown) {
            console.error('Error creating organization:', error);
            if ((error as { code?: string }).code === '23505') { // Unique violation
                toast.error('Organization slug already exists');
            } else {
                toast.error('Failed to create organization');
            }
            throw error;
        }
    };

    const addMember = async (userId: string, role: 'admin' | 'member' = 'member') => {
        if (!currentOrganization) return;
        try {
            const { error } = await supabase
                .from('organization_members')
                .insert({
                    organization_id: currentOrganization.id,
                    user_id: userId,
                    role,
                });

            if (error) throw error;
            toast.success('Member added successfully');
            await fetchOrganizations();
        } catch (error) {
            console.error('Error adding member:', error);
            toast.error('Failed to add member');
            throw error;
        }
    };

    const removeMember = async (userId: string) => {
        if (!currentOrganization) return;
        try {
            const { error } = await supabase
                .from('organization_members')
                .delete()
                .eq('organization_id', currentOrganization.id)
                .eq('user_id', userId);

            if (error) throw error;
            toast.success('Member removed successfully');
            await fetchOrganizations();
        } catch (error) {
            console.error('Error removing member:', error);
            toast.error('Failed to remove member');
            throw error;
        }
    };

    return (
        <OrganizationContext.Provider
            value={{
                organizations,
                currentOrganization,
                setCurrentOrganization,
                isLoading,
                createOrganization,
                refreshOrganizations: fetchOrganizations,
                addMember,
                removeMember,
            }}
        >
            {children}
        </OrganizationContext.Provider>
    );
};

export const useOrganization = () => {
    const context = useContext(OrganizationContext);
    if (context === undefined) {
        throw new Error('useOrganization must be used within an OrganizationProvider');
    }
    return context;
};

import { Device, types } from 'mediasoup-client';
import { SignalingService } from './signaling';

type Transport = types.Transport;
type Producer = types.Producer;
type Consumer = types.Consumer;
type RtpCapabilities = types.RtpCapabilities;
type RtpParameters = types.RtpParameters;
type DtlsParameters = types.DtlsParameters;

interface ResponseWithError {
  error?: string;
  [key: string]: unknown;
}

export class SFUManager {
  private device: Device;
  private signaling: SignalingService;
  private sendTransport: Transport | undefined;
  private recvTransport: Transport | undefined;
  private producers: Map<string, Producer> = new Map(); // source -> producer
  private consumers: Map<string, Consumer> = new Map(); // consumerId -> consumer
  private onTrack: (userId: string, track: MediaStreamTrack, kind: string) => void;
  private iceServers: RTCIceServer[] = [];

  constructor(
    signaling: SignalingService,
    onTrack: (userId: string, track: MediaStreamTrack, kind: string) => void
  ) {
    this.signaling = signaling;
    this.onTrack = onTrack;
    this.device = new Device();
  }

  async joinRoom(roomId: string, iceServers: RTCIceServer[] = []) {
    console.log('SFUManager: joinRoom called', roomId);
    this.iceServers = iceServers;

    // Reset device if already loaded to allow re-joining
    if (this.device && this.device.loaded) {
      console.log('SFUManager: Device already loaded, skipping load');
      return;
    }

    // 1. Get Router RTP Capabilities
    console.log('SFUManager: Emitting sfu:getRouterRtpCapabilities');
    const routerRtpCapabilities = await new Promise<RtpCapabilities>((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error('Timeout waiting for getRouterRtpCapabilities')), 5000);
      this.signaling.emit('sfu:getRouterRtpCapabilities', { roomId }, (data: RtpCapabilities | ResponseWithError) => {
        clearTimeout(timeout);
        const res = data as ResponseWithError;
        if (res.error) reject(res.error);
        else resolve(data as RtpCapabilities);
      });
    });
    console.log('SFUManager: Received Router RTP Capabilities');

    // 2. Load Device
    this.device = new Device(); // Re-initialize device if not loaded or if we want a fresh one
    await this.device.load({ routerRtpCapabilities });
    console.log('SFUManager: Device loaded');

    // 3. Create Send Transport
    console.log('SFUManager: Creating Send Transport');
    await this.createSendTransport(roomId);
    console.log('SFUManager: Send Transport Created');

    // 4. Create Recv Transport
    console.log('SFUManager: Creating Recv Transport');
    await this.createRecvTransport(roomId);
    console.log('SFUManager: Recv Transport Created');
  }

  async createSendTransport(roomId: string) {
    const transportParams = await new Promise<unknown>((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error('Timeout waiting for createWebRtcTransport')), 5000);
      this.signaling.emit('sfu:createWebRtcTransport', { roomId, forceTcp: false, producing: true }, (data: Transport | ResponseWithError) => {
        clearTimeout(timeout);
        const res = data as ResponseWithError;
        if (res.error) reject(res.error);
        else resolve(data as Transport);
      });
    });

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    this.sendTransport = this.device.createSendTransport({
      ...(transportParams as any),
      iceServers: this.iceServers,
    });

    this.sendTransport.on('connect', ({ dtlsParameters }: { dtlsParameters: DtlsParameters }, callback: () => void, errback: (error: Error) => void) => {
      this.signaling.emit(
        'sfu:connectWebRtcTransport',
        {
          roomId,
          transportId: this.sendTransport!.id,
          dtlsParameters,
        },
        (response: unknown) => {
          const res = response as ResponseWithError;
          if (res.error) errback(new Error(res.error));
          else {
            this.transportConnected = true;
            callback();
          }
        }
      );
    });

    this.sendTransport.on(
      'produce',
      ({ kind, rtpParameters, appData }: { kind: string; rtpParameters: RtpParameters; appData: any }, callback: (data: { id: string }) => void, errback: (error: Error) => void) => {
        this.signaling.emit(
          'sfu:produce',
          {
            roomId,
            transportId: this.sendTransport!.id,
            kind,
            rtpParameters,
            appData,
          },
          (response: unknown) => {
            const res = response as ResponseWithError;
            if (res.error) errback(new Error(res.error));
            else callback({ id: res.id as string });
          }
        );
      }
    );
  }

  async createRecvTransport(roomId: string) {
    const transportParams = await new Promise<unknown>((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error('Timeout waiting for createWebRtcTransport (recv)')), 5000);
      this.signaling.emit('sfu:createWebRtcTransport', { roomId, forceTcp: false, producing: false }, (data: Transport | ResponseWithError) => {
        clearTimeout(timeout);
        const res = data as ResponseWithError;
        if (res.error) reject(res.error);
        else resolve(data as Transport);
      });
    });

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    this.recvTransport = this.device.createRecvTransport({
      ...(transportParams as any),
      iceServers: this.iceServers,
    });

    this.recvTransport.on('connect', ({ dtlsParameters }: { dtlsParameters: DtlsParameters }, callback: () => void, errback: (error: Error) => void) => {
      this.signaling.emit(
        'sfu:connectWebRtcTransport',
        {
          roomId,
          transportId: this.recvTransport!.id,
          dtlsParameters,
        },
        (response: unknown) => {
          const res = response as ResponseWithError;
          if (res.error) errback(new Error(res.error));
          else callback();
        }
      );
    });
  }

  async produce(track: MediaStreamTrack, source: string = 'webcam') {
    // Wait for transport to be ready
    const ready = await this.waitForTransportReady();
    if (!ready) {
      throw new Error('Send transport not created or not connected');
    }

    if (!this.sendTransport) throw new Error('Send transport not created');

    const producer = await this.sendTransport.produce({ track, appData: { source } });
    this.producers.set(source, producer);

    producer.on('trackended', () => {
      this.closeProducer(source);
    });

    return producer;
  }

  async replaceTrack(track: MediaStreamTrack, source: string = 'webcam') {
    const producer = this.producers.get(source);
    if (producer) {
      await producer.replaceTrack({ track });
    } else {
      await this.produce(track, source);
    }
  }

  closeProducer(source: string) {
    const producer = this.producers.get(source);
    if (producer) {
      producer.close();
      this.producers.delete(source);
    }
  }

  getProducer(source: string) {
    return this.producers.get(source);
  }

  private transportConnected = false;

  isTransportReady(): boolean {
    return !!this.sendTransport;
  }

  async waitForTransportReady(maxWait = 5000): Promise<boolean> {
    const startTime = Date.now();

    // Poll for sendTransport existence
    while (!this.sendTransport) {
      if (Date.now() - startTime > maxWait) {
        console.warn('Timed out waiting for sendTransport creation');
        return false;
      }
      await new Promise(resolve => setTimeout(resolve, 100));
    }

    return true;
  }

  async consume(roomId: string, producerId: string, socketId: string, kind: string) {
    if (!this.recvTransport) throw new Error('Recv transport not created');

    const { rtpCapabilities } = this.device;

    const data = await new Promise<ResponseWithError>((resolve, reject) => {
      this.signaling.emit(
        'sfu:consume',
        {
          roomId,
          transportId: this.recvTransport!.id,
          producerId,
          rtpCapabilities,
        },
        (response: unknown) => {
          const res = response as ResponseWithError;
          if (res.error) reject(res.error);
          else resolve(res);
        }
      );
    });

    const consumer = await this.recvTransport.consume({
      id: data.id as string,
      producerId: data.producerId as string,
      kind: data.kind as 'audio' | 'video',
      rtpParameters: data.rtpParameters as RtpParameters,
    });

    // Resume consumer (it starts paused)
    await new Promise<void>((resolve) => {
      this.signaling.emit('sfu:resumeConsumer', { roomId, consumerId: consumer.id }, () =>
        resolve()
      );
    });

    this.consumers.set(consumer.id, consumer);

    this.onTrack(socketId, consumer.track, kind);

    consumer.on('transportclose', () => {
      this.consumers.delete(consumer.id);
    });
  }

  closeAll() {
    this.sendTransport?.close();
    this.recvTransport?.close();
    this.producers.forEach((p) => p.close());
    this.consumers.forEach((c) => c.close());
    this.transportConnected = false;
  }
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { useWebSocket } from '@/hooks/useWebSocket';
import Navbar from '@/components/Navbar';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  CardFooter,
} from '@/components/ui/card';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Plus, Users, LogIn, Lock, Unlock, RefreshCw, Globe, Link as LinkIcon, ShieldCheck } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { toast } from 'sonner';

import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { useOrganization } from '@/contexts/OrganizationContext';
import { CreateOrganizationModal } from '@/components/CreateOrganizationModal';
import { OrganizationSettingsModal } from '@/components/OrganizationSettingsModal';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Building2, Settings } from 'lucide-react';

const Dashboard = () => {
  const { user } = useAuth();
  const { isConnected, createRoom, joinRoom, getRecentRooms } = useWebSocket();
  const navigate = useNavigate();

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [recentRooms, setRecentRooms] = useState<any[]>([]);
  const [roomName, setRoomName] = useState('');
  const [newRoomPassword, setNewRoomPassword] = useState('');
  const [accessType, setAccessType] = useState<'public' | 'password' | 'invite' | 'organization'>('public');
  const [joinRoomId, setJoinRoomId] = useState('');
  const [joinRoomPassword, setJoinRoomPassword] = useState('');
  const [isJoinDialogOpen, setIsJoinDialogOpen] = useState(false);

  const { organizations, currentOrganization, setCurrentOrganization } = useOrganization();
  const [isCreateOrgModalOpen, setIsCreateOrgModalOpen] = useState(false);
  const [isOrgSettingsModalOpen, setIsOrgSettingsModalOpen] = useState(false);

  useEffect(() => {
    if (!isConnected) return;

    // Initial fetch with callback
    getRecentRooms((rooms) => {
      setRecentRooms(rooms as typeof recentRooms);
    });

    // Poll for recent rooms every 3 seconds when connected
    const interval = setInterval(() => {
      if (isConnected) {
        getRecentRooms((rooms) => {
          setRecentRooms(rooms as typeof recentRooms);
        });
      }
    }, 3000);

    return () => clearInterval(interval);
  }, [getRecentRooms, isConnected]);

  const handleCreateRoom = () => {
    if (!roomName.trim()) {
      toast.error('Please enter a room name');
      return;
    }

    // Generate a 6-digit random alphanumeric key
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let roomId = '';
    for (let i = 0; i < 6; i++) {
      roomId += chars.charAt(Math.floor(Math.random() * chars.length));
    }

    // Pass a callback to navigate after successful join
    createRoom(roomId, roomName, newRoomPassword, accessType, () => {
      toast.success(`Room created! Key: ${roomId}`);
      navigate(`/room/${roomId}`);
    }, currentOrganization?.id);
  };

  const handleJoinRoom = async (input: string, requiresPassword?: boolean) => {
    let roomId = input;
    let token: string | undefined;

    // Check if input is a URL
    try {
      const url = new URL(input);
      // Extract roomId from path (e.g., /room/123 -> 123)
      const pathParts = url.pathname.split('/');
      const idFromPath = pathParts[pathParts.length - 1];
      if (idFromPath) {
        roomId = idFromPath;
      }
      // Extract token from query params
      const tokenFromUrl = url.searchParams.get('token');
      if (tokenFromUrl) {
        token = tokenFromUrl;
      }
    } catch (e) {
      // Not a URL, treat as plain roomId
    }

    // If we already know the password requirement (e.g., from recent rooms), use it
    if (requiresPassword) {
      setJoinRoomId(roomId);
      setIsJoinDialogOpen(true);
      return;
    }

    // Otherwise, fetch room info to determine if a password is needed
    try {
      // Convert ws:// to http:// for HTTP requests
      const baseUrl = (import.meta.env.VITE_WS_URL || 'http://localhost:3001').replace(/^ws:/, 'http:');
      const response = await fetch(
        `${baseUrl}/api/room-info/${roomId}`
      );
      if (!response.ok) {
        toast.error('Room not found');
        return;
      }
      const data = await response.json();
      if (data.requiresPassword) {
        setJoinRoomId(roomId);
        setIsJoinDialogOpen(true);
      } else {
        joinRoom(roomId, undefined, token, () => {
          navigate(`/room/${roomId}`);
        });
      }
    } catch (e) {
      console.error(e);
      toast.error('Failed to check room info');
    }
  };

  const handleJoinWithPassword = () => {
    if (!joinRoomPassword) {
      toast.error('Please enter a password');
      return;
    }

    joinRoom(joinRoomId, joinRoomPassword, undefined, () => {
      navigate(`/room/${joinRoomId}`);
    });

    setIsJoinDialogOpen(false);
    setJoinRoomPassword('');
  };

  return (
    <div className='min-h-screen bg-background'>
      <Navbar />

      <div className='container pb-10 pt-32'>
        <div className='flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4'>
          <div>
            <h1 className='text-3xl font-bold tracking-tight'>Dashboard</h1>
            <p className='text-muted-foreground'>
              Welcome back, {user?.user_metadata?.display_name || user?.email?.split('@')[0]}
            </p>
          </div>

          <div className='flex gap-2 items-center'>
            <div className="w-[200px]">
              <Select
                value={currentOrganization?.id || 'personal'}
                onValueChange={(value) => {
                  if (value === 'create') {
                    setIsCreateOrgModalOpen(true);
                  } else if (value === 'personal') {
                    setCurrentOrganization(null);
                  } else {
                    const org = organizations.find((o) => o.id === value);
                    setCurrentOrganization(org || null);
                  }
                }}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select Organization" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="personal">
                    <div className="flex items-center">
                      <Users className="w-4 h-4 mr-2" />
                      Personal
                    </div>
                  </SelectItem>
                  {organizations.map((org) => (
                    <SelectItem key={org.id} value={org.id}>
                      <div className="flex items-center">
                        <Building2 className="w-4 h-4 mr-2" />
                        {org.name}
                      </div>
                    </SelectItem>
                  ))}
                  <SelectItem value="create" className="text-primary font-medium">
                    <div className="flex items-center">
                      <Plus className="w-4 h-4 mr-2" />
                      Create Organization
                    </div>
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>
            {currentOrganization && (
              <Button variant="ghost" size="icon" onClick={() => setIsOrgSettingsModalOpen(true)}>
                <Settings className="w-4 h-4" />
              </Button>
            )}
            <Button variant='outline' onClick={() => getRecentRooms()}>
              <RefreshCw className='w-4 h-4 mr-2' />
              Refresh
            </Button>
          </div>
        </div>

        <div className='grid gap-6 md:grid-cols-2 lg:grid-cols-3'>
          {/* Create Room Card */}
          <Card className='bg-primary/5 border-primary/20'>
            <CardHeader>
              <CardTitle className='flex items-center gap-2'>
                <Plus className='w-5 h-5 text-primary' />
                Create New Room
              </CardTitle>
              <CardDescription>Start a new secure collaboration session</CardDescription>
            </CardHeader>
            <CardContent className='space-y-4'>
              <div className='space-y-2'>
                <Label htmlFor='room-name'>Room Name</Label>
                <Input
                  id='room-name'
                  placeholder='e.g. Project Alpha'
                  value={roomName}
                  onChange={(e) => setRoomName(e.target.value)}
                />
              </div>

              <div className='space-y-3'>
                <Label className='text-base font-medium'>Access Type</Label>
                <div className='grid grid-cols-1 md:grid-cols-3 gap-3'>
                  {[
                    {
                      id: 'public',
                      label: 'Public',
                      icon: Globe,
                      desc: 'Open to everyone',
                      color: 'text-blue-400',
                      bg: 'bg-blue-400/10',
                      border: 'border-blue-400/50'
                    },
                    {
                      id: 'password',
                      label: 'Private',
                      icon: Lock,
                      desc: 'Password required',
                      color: 'text-amber-400',
                      bg: 'bg-amber-400/10',
                      border: 'border-amber-400/50'
                    },
                    {
                      id: 'invite',
                      label: 'Invite',
                      icon: LinkIcon,
                      desc: 'Token link only',
                      color: 'text-purple-400',
                      bg: 'bg-purple-400/10',
                      border: 'border-purple-400/50'
                    },
                    ...(currentOrganization ? [{
                      id: 'organization',
                      label: 'Organization',
                      icon: Building2,
                      desc: 'Members only',
                      color: 'text-indigo-400',
                      bg: 'bg-indigo-400/10',
                      border: 'border-indigo-400/50'
                    }] : [])
                  ].map((type) => (
                    <div
                      key={type.id}
                      onClick={() => setAccessType(type.id as any)}
                      className={`
                        relative cursor-pointer rounded-xl border-2 p-3 transition-all duration-300 ease-in-out
                        hover:scale-105 hover:shadow-lg
                        ${accessType === type.id
                          ? `${type.border} ${type.bg} shadow-md scale-105`
                          : 'border-muted/40 hover:border-muted hover:bg-muted/20'
                        }
                      `}
                    >
                      <div className='flex flex-col items-center text-center gap-2'>
                        <div className={`p-2 rounded-full bg-background/50 ${accessType === type.id ? type.color : 'text-muted-foreground'}`}>
                          <type.icon className='w-5 h-5' />
                        </div>
                        <div>
                          <p className={`font-semibold text-sm ${accessType === type.id ? 'text-foreground' : 'text-muted-foreground'}`}>
                            {type.label}
                          </p>
                          <p className='text-[10px] text-muted-foreground/80 uppercase tracking-wider font-medium mt-0.5'>
                            {type.desc}
                          </p>
                        </div>
                      </div>
                      {accessType === type.id && (
                        <div className='absolute top-2 right-2'>
                          <span className='relative flex h-2 w-2'>
                            <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${type.color.replace('text-', 'bg-')}`}></span>
                            <span className={`relative inline-flex rounded-full h-2 w-2 ${type.color.replace('text-', 'bg-')}`}></span>
                          </span>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <div className={`space-y-2 overflow-hidden transition-all duration-300 ease-in-out ${accessType === 'password' ? 'max-h-24 opacity-100 mt-4' : 'max-h-0 opacity-0'}`}>
                <Label htmlFor='room-pass' className='text-amber-400 flex items-center gap-2'>
                  <Lock className='w-3 h-3' /> Set Room Password
                </Label>
                <Input
                  id='room-pass'
                  type='password'
                  placeholder='Enter a strong password...'
                  value={newRoomPassword}
                  onChange={(e) => setNewRoomPassword(e.target.value)}
                  className='border-amber-400/30 focus:border-amber-400 focus:ring-amber-400/20 bg-amber-400/5'
                />
              </div>
            </CardContent>
            <CardFooter>
              <Button className='w-full' onClick={handleCreateRoom}>
                Create & Join
              </Button>
            </CardFooter>
          </Card>

          {/* Join Room Card */}
          <Card>
            <CardHeader>
              <CardTitle className='flex items-center gap-2'>
                <LogIn className='w-5 h-5' />
                Join by ID or Link
              </CardTitle>
              <CardDescription>Enter a room ID or paste a link to join</CardDescription>
            </CardHeader>
            <CardContent className='space-y-4'>
              <div className='space-y-2'>
                <Label htmlFor='join-id'>Room ID or Link</Label>
                <Input
                  id='join-id'
                  placeholder='Enter Room ID or paste link'
                  value={joinRoomId}
                  onChange={(e) => setJoinRoomId(e.target.value)}
                />
              </div>
            </CardContent>
            <CardFooter>
              <Button
                variant='secondary'
                className='w-full'
                onClick={() => handleJoinRoom(joinRoomId)}
              >
                Join Room
              </Button>
            </CardFooter>
          </Card>
        </div>

        <div className='mt-12'>
          <h2 className='text-2xl font-semibold mb-6 flex items-center gap-2'>
            <Users className='w-6 h-6' />
            Active Rooms
          </h2>

          {recentRooms.length === 0 ? (
            <div className='text-center py-12 border rounded-lg bg-muted/10 border-dashed'>
              <p className='text-muted-foreground'>
                No active rooms found. Create one to get started!
              </p>
            </div>
          ) : (
            <div className='grid gap-4 md:grid-cols-2 lg:grid-cols-3'>
              {recentRooms.map((room) => (
                <Card
                  key={room.id}
                  className='hover:shadow-md transition-shadow cursor-pointer'
                  onClick={() => handleJoinRoom(room.id, room.requiresPassword)}
                >
                  <CardHeader className='pb-2'>
                    <div className='flex justify-between items-start'>
                      <CardTitle className='text-lg font-medium'>{room.name || room.id}</CardTitle>
                      {room.requiresPassword ? (
                        <Lock className='w-4 h-4 text-amber-500' />
                      ) : (
                        <Unlock className='w-4 h-4 text-green-500' />
                      )}
                    </div>
                    <CardDescription>
                      ID: {room.id} ΓÇó Created{' '}
                      {formatDistanceToNow(new Date(room.createdAt), { addSuffix: true })}
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    <div className='flex items-center gap-2 text-sm text-muted-foreground'>
                      <Users className='w-4 h-4' />
                      {room.userCount} participant{room.userCount !== 1 && 's'}
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Password Dialog */}
      <Dialog open={isJoinDialogOpen} onOpenChange={setIsJoinDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Password Required</DialogTitle>
            <DialogDescription>
              This room is protected. Please enter the password to join.
            </DialogDescription>
          </DialogHeader>
          <div className='py-4'>
            <Label htmlFor='join-pass'>Password</Label>
            <Input
              id='join-pass'
              type='password'
              value={joinRoomPassword}
              onChange={(e) => setJoinRoomPassword(e.target.value)}
              className='mt-2'
            />
          </div>
          <DialogFooter>
            <Button onClick={handleJoinWithPassword}>Join Room</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <CreateOrganizationModal
        open={isCreateOrgModalOpen}
        onOpenChange={setIsCreateOrgModalOpen}
      />

      <OrganizationSettingsModal
        open={isOrgSettingsModalOpen}
        onOpenChange={setIsOrgSettingsModalOpen}
      />
    </div>
  );
};

export default Dashboard;
